SELECT average_length_cm
FROM dimensions
WHERE species_id = 1;

SELECT max_mass_g AS max_recorded_mass
FROM mass_data
WHERE species_id = 1;

SELECT AVG(mean_hra_m2) AS average_mean_hra
FROM habitat_area
WHERE habitat_type = 'lake' AND habitat_quality = 'pristine';

SELECT species_id
FROM species_conservation
WHERE status = 'Near Threatened';

SELECT species_id
FROM habitat_area
WHERE mean_hra_m2 = (SELECT MAX(mean_hra_m2) FROM habitat_area);

SELECT species_id, realm
FROM ecological_data
WHERE thermoregulation = 'ectotherm';
